insert into public.drug_interactions (drug_1, drug_2, severity, title_th, description_th, advice_th) values
('aspirin','warfarin','severe','ห้ามรับประทานยาคู่นี้ร่วมกัน','ตรวจพบว่ายาคู่นี้อยู่ในกลุ่มห้ามใช้ร่วมกัน ระบบไม่แสดงรายละเอียดผลกระทบเพื่อความปลอดภัย','อย่าปรับหรือหยุดยาที่ใช้อยู่เอง ให้ติดต่อแพทย์หรือเภสัชกรทันที'),
