insert into public.food_interactions (code, food_th, keywords, medicine_codes, disease_codes, severity, description_th) values
('grapefruit','เกรปฟรุต/ส้มโอ','{เกรปฟรุต,grapefruit,น้ำส้มโอ,ส้มโอ}','{simvastatin,amlodipine}','{}','severe','อาจเพิ่มระดับยาบางชนิดในเลือด ควรสอบถามเภสัชกรตามชื่อผลิตภัณฑ์และปริมาณที่กิน'),
('licorice','ชะเอมเทศ','{ชะเอม,licorice,ชะเอมเทศ}','{digoxin}','{hypertension,heart}','severe','อาจกระทบโพแทสเซียม ความดัน และจังหวะหัวใจ'),
('sugar','อาหารหวานจัด','{น้ำผึ้ง,ชาเย็น,น้ำหวาน,ทุเรียน,ลำไย}','{}','{diabetes}','severe','อาจทำให้ควบคุมระดับน้ำตาลได้ยาก'),
('sodium','อาหารเค็มจัด/โซเดียมสูง','{เค็ม,มาม่า,น้ำปลา,ปลาร้า,ของหมักดอง}','{}','{hypertension,kidney,heart}','severe','เพิ่มภาระต่อความดัน หัวใจ และไต'),
('alcohol','แอลกอฮอล์/ยาดอง','{แอลกอฮอล์,เหล้า,เบียร์,ไวน์,ยาดอง}','{}','{liver,heart,hypertension,diabetes,stomach}','severe','อาจเพิ่มผลข้างเคียงของยาและทำให้โรคประจำตัวควบคุมยากขึ้น'),
('potassium','อาหารโพแทสเซียมสูง','{กล้วย,มะเขือเทศ,แคนตาลูป,มะละกอ}','{enalapril,losartan,spironolactone}','{kidney}','severe','ผู้ป่วยไตหรือผู้ใช้ยาบางชนิดอาจมีโพแทสเซียมสูง ต้องปรึกษาทีมรักษาเรื่องปริมาณที่เหมาะสม')
