on conflict (code) do update set name_en=excluded.name_en, name_th=excluded.name_th, category=excluded.category, common_dosages_mg=excluded.common_dosages_mg, description_th=excluded.description_th;

on conflict (drug_1, drug_2) do update set severity=excluded.severity, title_th=excluded.title_th, description_th=excluded.description_th, advice_th=excluded.advice_th;

on conflict (code) do update set food_th=excluded.food_th, keywords=excluded.keywords, medicine_codes=excluded.medicine_codes, disease_codes=excluded.disease_codes, severity=excluded.severity, description_th=excluded.description_th;
